import numpy as np
import os
from .loader import load_file as original_load_file

def smooth_data(data, window_size=5):
    """
    1D 이동 평균 필터를 사용하여 데이터 스무딩 (Valid padding)
    """
    if window_size <= 1:
        return data
    
    kernel = np.ones(window_size) / window_size
    # np.convolve는 1차원만 지원하므로 각 컬럼별로 적용
    smoothed = np.zeros_like(data)
    
    for i in range(data.shape[1]):
        # mode='same'을 사용하여 원본 길이를 유지하되, 경계 부분은 원본 값 유지 또는 패딩 처리
        # 여기서는 간단히 edge padding 효과를 위해 처음과 끝 값을 복사해서 처리
        col = data[:, i]
        pad_width = window_size // 2
        padded = np.pad(col, (pad_width, pad_width), mode='edge')
        conv = np.convolve(padded, kernel, mode='valid')
        
        # 윈도우 크기에 따라 길이가 약간 달라질 수 있으므로 맞춤
        if len(conv) > len(col):
            conv = conv[:len(col)]
        smoothed[:, i] = conv
        
    return smoothed

def load_multiple_files_v(filepaths, use_vel=True, vel_window=10):
    """
    여러 파일을 로드하고 속도 데이터 정제 후 합칩니다.
    """
    X_list = []
    Y_list = []
    
    for fp in filepaths:
        if not os.path.exists(fp):
            print(f"[WARN] File not found: {fp}")
            continue
            
        data = original_load_file(fp)
        X, Y = extract_features_v(data, use_vel=use_vel, vel_window=vel_window)
        X_list.append(X)
        Y_list.append(Y)
        
    if not X_list:
        return np.array([]), np.array([])
        
    return np.concatenate(X_list, axis=0), np.concatenate(Y_list, axis=0)

def extract_features_v(data, use_vel=True, vel_window=10):
    """
    데이터에서 Feature(X)와 Target(Y)을 추출합니다.
    use_vel=True일 경우 속도 데이터에 스무딩을 적용합니다.
    """
    # data columns:
    # 0: timestamp
    # 1~6: joint pos (deg)
    # 7~12: joint vel (deg/s)
    # 13~20: prox
    # 21~28: raw (target)
    # 29~36: tof

    # 1. Joint Position -> Sin/Cos Encoding
    joint_pos_deg = data[:, 1:7]
    joint_pos_rad = np.deg2rad(joint_pos_deg)
    sin_j = np.sin(joint_pos_rad)
    cos_j = np.cos(joint_pos_rad)
    
    features = [sin_j, cos_j]
    
    # 2. Joint Velocity (Optional with Smoothing)
    if use_vel:
        joint_vel = data[:, 7:13]
        # 속도 데이터 정제 (Smoothing)
        joint_vel_smooth = smooth_data(joint_vel, window_size=vel_window)
        # 정규화에 유리하도록 스케일링 (선택 사항, 여기서는 그대로 사용하고 Dataset에서 정규화)
        features.append(joint_vel_smooth)
        
    X = np.concatenate(features, axis=1) # (N, 12) or (N, 18)
    
    # 3. Target (Raw)
    Y = data[:, 21:29]
    
    return X, Y